export interface Chapter {
  id: number;
  title: string;
  pageStart?: number; // Optional, AI estimated
  pageEnd?: number;   // Optional, AI estimated
  description?: string;
}

export interface BookStructure {
  id: string; // Unique ID for the book in library
  title: string;
  author: string;
  chapters: Chapter[];
  bookmarks: number[]; // Array of chapter IDs
}

export interface Concept {
  term: string;
  definition: string;
  visualPrompt: string;
}

export interface DictionaryEntry {
  word: string;
  context: string;
  definition: string;
}

export interface PodcastState {
  audioUrl: string | null;
  isLoading: boolean;
  script: string | null;
}

export interface VisualState {
  concepts: Concept[];
  generatedImages: Record<string, string>; // term -> base64/url
  isLoading: boolean;
}

export interface DictionaryState {
  entries: DictionaryEntry[];
  isLoading: boolean;
}

export interface VideoState {
  videoUrl: string | null;
  isLoading: boolean;
  progressMessage: string;
}

export interface FileContext {
  content: string; // Base64 string for PDF, or raw text string for text files
  mimeType: string;
  isText: boolean; // Flag to determine how to send to Gemini
}

export interface NotebookItem {
  id: string;
  text: string;
  type: 'word' | 'phrase' | 'sentence';
  definition?: string;
  timestamp: number;
  sourceChapter?: string;
  bookTitle?: string;
  bookAuthor?: string;
  comment?: string;
  contextSource?: string; // e.g. "Neural_Podcast", "Input_Stream", "Decoded_Layer"
}

export interface MindMapNode {
  id: string;
  label: string;
  children?: MindMapNode[];
  type?: 'root' | 'category' | 'item';
  note?: string; // Additional context
  isCollapsed?: boolean; // UI state
}

export enum AppView {
  UPLOAD = 'UPLOAD',
  DASHBOARD = 'DASHBOARD'
}

export enum Tab {
  AUDIOBOOK = 'AUDIOBOOK',
  DICTIONARY = 'DICTIONARY',
  CONCEPTS = 'CONCEPTS',
  PODCAST = 'PODCAST',
  ANIMATION = 'ANIMATION',
  NOTEBOOK = 'NOTEBOOK'
}

export type ThemeColor = 'indigo' | 'emerald' | 'rose' | 'amber' | 'cyan';

export interface AppSettings {
  targetLanguage: string;
  highlightColor: ThemeColor;
  textSize: 'sm' | 'base' | 'lg' | 'xl';
  lineHeight: 'tight' | 'normal' | 'relaxed' | 'loose';
  letterSpacing: 'tighter' | 'normal' | 'wide' | 'wider';
  font: 'Inter' | 'Merriweather' | 'Playfair Display' | 'Roboto Mono' | 'Open Sans' | 'Orbitron' | 'Cinzel' | 'Source Code Pro' | 'Crimson Text';
}

export interface LibraryItem {
  book: BookStructure;
  fileContext: FileContext;
  uploadDate: number;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const abortMapRef = useRef<boolean>(false);

  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
            setShowExportMenu(false);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               <div className={`flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800 transition-opacity duration-200 ${isMindMapMode ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
                    <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                    <select 
                        disabled={isMindMapMode}
                        value={activeFilter} 
                        onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                        className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                    >
                        <option value="all">ALL ITEMS</option>
                        <option value="word">WORDS</option>
                        <option value="phrase">PHRASES</option>
                        <option value="sentence">SENTENCES</option>
                    </select>
                    <div className="w-[1px] h-4 bg-zinc-700"></div>
                    <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                    <select 
                        disabled={isMindMapMode}
                        value={sortOrder} 
                        onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                        className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                    >
                        <option value="newest">NEWEST</option>
                        <option value="oldest">OLDEST</option>
                        <option value="az">A-Z</option>
                        <option value="za">Z-A</option>
                    </select>
               </div>

               {isMindMapMode ? (
                   <div className="flex items-center gap-2 animate-fade-in">
                       <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                           <div className="relative" ref={exportMenuRef}>
                               <button 
                                   onClick={() => setShowExportMenu(!showExportMenu)} 
                                   className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all ${showExportMenu ? 'text-[#00f3ff] bg-[#00f3ff]/10' : 'text-zinc-400 hover:text-white hover:bg-zinc-900'}`}
                               >
                                   <Download size={14} /> EXPORT
                               </button>
                               {showExportMenu && (
                                   <div className="absolute top-full right-0 mt-2 w-32 bg-[#0a0a0c] border border-zinc-800 rounded-sm shadow-[0_4px_20px_rgba(0,0,0,0.5)] z-50 flex flex-col p-1 animate-fade-in">
                                        <button onClick={() => { exportToXmind(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Share2 size={12}/> XMIND</button>
                                        <button onClick={() => { exportToDocx(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><FileText size={12}/> DOCX</button>
                                        <button onClick={() => { exportToPdf(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Download size={12}/> PDF</button>
                                   </div>
                               )}
                           </div>
                           <div className="w-[1px] h-4 bg-zinc-700"></div>
                           <button onClick={() => setIsMindMapMode(false)} className="flex items-center gap-2 px-4 py-1.5 text-zinc-400 hover:text-[#ff003c] rounded-sm text-xs font-bold font-mono uppercase transition-all">
                               <X size={14} /> EXIT MAP
                           </button>
                       </div>
                   </div>
               ) : (
                   <button onClick={handleInitiateMindMap} disabled={filteredItems.length === 0} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}>
                       {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                       {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
                   </button>
               )}
           </div>
       </div>

       {isMindMapMode ? (
           <div className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" ref={mapContainerRef}>
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               <div className="absolute bottom-4 right-4 flex gap-2 z-20">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomIn size={16}/></button>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-20 cursor-grab active:cursor-grabbing">
                       <svg width="2400" height="1800" viewBox="-400 -900 2400 1800" style={{ transform: `scale(${mapZoom})`, transition: 'transform 0.2s' }}>
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
// Added missing Loader import from the local UI component directory
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const abortMapRef = useRef<boolean>(false);

  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
            setShowExportMenu(false);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               <div className={`flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800 transition-opacity duration-200 ${isMindMapMode ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
                    <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                    <select 
                        disabled={isMindMapMode}
                        value={activeFilter} 
                        onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                        className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                    >
                        <option value="all">ALL ITEMS</option>
                        <option value="word">WORDS</option>
                        <option value="phrase">PHRASES</option>
                        <option value="sentence">SENTENCES</option>
                    </select>
                    <div className="w-[1px] h-4 bg-zinc-700"></div>
                    <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                    <select 
                        disabled={isMindMapMode}
                        value={sortOrder} 
                        onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                        className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                    >
                        <option value="newest">NEWEST</option>
                        <option value="oldest">OLDEST</option>
                        <option value="az">A-Z</option>
                        <option value="za">Z-A</option>
                    </select>
               </div>

               {isMindMapMode ? (
                   <div className="flex items-center gap-2 animate-fade-in">
                       <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                           <div className="relative" ref={exportMenuRef}>
                               <button 
                                   onClick={() => setShowExportMenu(!showExportMenu)} 
                                   className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all ${showExportMenu ? 'text-[#00f3ff] bg-[#00f3ff]/10' : 'text-zinc-400 hover:text-white hover:bg-zinc-900'}`}
                               >
                                   <Download size={14} /> EXPORT
                               </button>
                               {showExportMenu && (
                                   <div className="absolute top-full right-0 mt-2 w-32 bg-[#0a0a0c] border border-zinc-800 rounded-sm shadow-[0_4px_20px_rgba(0,0,0,0.5)] z-50 flex flex-col p-1 animate-fade-in">
                                        <button onClick={() => { exportToXmind(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Share2 size={12}/> XMIND</button>
                                        <button onClick={() => { exportToDocx(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><FileText size={12}/> DOCX</button>
                                        <button onClick={() => { exportToPdf(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Download size={12}/> PDF</button>
                                   </div>
                               )}
                           </div>
                           <div className="w-[1px] h-4 bg-zinc-700"></div>
                           <button onClick={() => setIsMindMapMode(false)} className="flex items-center gap-2 px-4 py-1.5 text-zinc-400 hover:text-[#ff003c] rounded-sm text-xs font-bold font-mono uppercase transition-all">
                               <X size={14} /> EXIT MAP
                           </button>
                       </div>
                   </div>
               ) : (
                   <button onClick={handleInitiateMindMap} disabled={filteredItems.length === 0} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}>
                       {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                       {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
                   </button>
               )}
           </div>
       </div>

       {isMindMapMode ? (
           <div className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" ref={mapContainerRef}>
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               <div className="absolute bottom-4 right-4 flex gap-2 z-20">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomIn size={16}/></button>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-20 cursor-grab active:cursor-grabbing">
                       <svg width="2400" height="1800" viewBox="-400 -900 2400 1800" style={{ transform: `scale(${mapZoom})`, transition: 'transform 0.2s' }}>
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
// Added missing Loader import from the local UI component directory
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const abortMapRef = useRef<boolean>(false);

  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
            setShowExportMenu(false);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               {/* Controls Group: Switch between Filter/Sort or Export/Exit */}
               <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                    {!isMindMapMode ? (
                        <React.Fragment>
                            <div className="flex items-center">
                                <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                                <select 
                                    value={activeFilter} 
                                    onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                                    className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                                >
                                    <option value="all">ALL ITEMS</option>
                                    <option value="word">WORDS</option>
                                    <option value="phrase">PHRASES</option>
                                    <option value="sentence">SENTENCES</option>
                                </select>
                            </div>
                            <div className="w-[1px] h-4 bg-zinc-700"></div>
                            <div className="flex items-center">
                                <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                                <select 
                                    value={sortOrder} 
                                    onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                                    className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                                >
                                    <option value="newest">NEWEST</option>
                                    <option value="oldest">OLDEST</option>
                                    <option value="az">A-Z</option>
                                    <option value="za">Z-A</option>
                                </select>
                            </div>
                        </React.Fragment>
                    ) : (
                        <React.Fragment>
                            <div className="relative flex items-center" ref={exportMenuRef}>
                                <div className="p-1.5 text-zinc-500"><Download size={16} /></div>
                                <button 
                                    onClick={() => setShowExportMenu(!showExportMenu)} 
                                    className={`bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] text-left hover:text-white transition-colors`}
                                >
                                    EXPORT
                                </button>
                                {showExportMenu && (
                                    <div className="absolute top-full left-0 mt-2 w-32 bg-[#0a0a0c] border border-zinc-800 rounded-sm shadow-[0_4px_20px_rgba(0,0,0,0.5)] z-50 flex flex-col p-1 animate-fade-in">
                                         <button onClick={() => { exportToXmind(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Share2 size={12}/> XMIND</button>
                                         <button onClick={() => { exportToDocx(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><FileText size={12}/> DOCX</button>
                                         <button onClick={() => { exportToPdf(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Download size={12}/> PDF</button>
                                    </div>
                                )}
                            </div>
                            <div className="w-[1px] h-4 bg-zinc-700"></div>
                            <div className="flex items-center">
                                <div className="p-1.5 text-zinc-500"><X size={16} /></div>
                                <button 
                                    onClick={() => setIsMindMapMode(false)}
                                    className="bg-transparent text-xs text-[#ff003c] outline-none cursor-pointer font-mono uppercase w-[120px] text-left hover:text-white transition-colors"
                                >
                                    EXIT MAP
                                </button>
                            </div>
                        </React.Fragment>
                    )}
               </div>

               {/* Always visible Initiate Button */}
               <button 
                  onClick={handleInitiateMindMap} 
                  disabled={filteredItems.length === 0} 
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}
               >
                   {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                   {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
               </button>
           </div>
       </div>

       {isMindMapMode ? (
           <div className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" ref={mapContainerRef}>
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               <div className="absolute bottom-4 right-4 flex gap-2 z-20">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="p-2 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors"><ZoomIn size={16}/></button>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-20 cursor-grab active:cursor-grabbing">
                       <svg width="2400" height="1800" viewBox="-400 -900 2400 1800" style={{ transform: `scale(${mapZoom})`, transition: 'transform 0.2s' }}>
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus, LogOut } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const abortMapRef = useRef<boolean>(false);

  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
            setShowExportMenu(false);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                    <div className="flex items-center">
                        <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                        <select 
                            value={activeFilter} 
                            onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="all">ALL ITEMS</option>
                            <option value="word">WORDS</option>
                            <option value="phrase">PHRASES</option>
                            <option value="sentence">SENTENCES</option>
                        </select>
                    </div>
                    <div className="w-[1px] h-4 bg-zinc-700"></div>
                    <div className="flex items-center">
                        <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                        <select 
                            value={sortOrder} 
                            onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="newest">NEWEST</option>
                            <option value="oldest">OLDEST</option>
                            <option value="az">A-Z</option>
                            <option value="za">Z-A</option>
                        </select>
                    </div>
               </div>

               <button 
                  onClick={handleInitiateMindMap} 
                  disabled={filteredItems.length === 0} 
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}
               >
                   {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                   {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
               </button>
           </div>
       </div>

       {isMindMapMode ? (
           <div className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" ref={mapContainerRef}>
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               {/* Floating Controls in Top Right */}
               <div className="absolute top-4 right-4 flex gap-2 z-50">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="p-2 bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-sm transition-colors shadow-lg"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="p-2 bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-sm transition-colors shadow-lg"><ZoomIn size={16}/></button>

                    {/* Export Dropdown Styled Button */}
                    <div className="flex items-center bg-black/50 p-1 rounded-sm border border-zinc-800 relative" ref={exportMenuRef}>
                         <div className="p-1.5 text-zinc-500"><Download size={16} /></div>
                         <button 
                             onClick={() => setShowExportMenu(!showExportMenu)} 
                             className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] text-left hover:text-white transition-colors"
                         >
                             EXPORT
                         </button>
                         {showExportMenu && (
                             <div className="absolute top-full left-0 mt-2 w-32 bg-[#0a0a0c] border border-zinc-800 rounded-sm shadow-[0_4px_20px_rgba(0,0,0,0.5)] z-[60] flex flex-col p-1 animate-fade-in">
                                  <button onClick={() => { exportToXmind(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Share2 size={12}/> XMIND</button>
                                  <button onClick={() => { exportToDocx(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><FileText size={12}/> DOCX</button>
                                  <button onClick={() => { exportToPdf(); setShowExportMenu(false); }} className="text-left px-3 py-2 text-[10px] font-mono text-zinc-400 hover:text-white hover:bg-zinc-900 uppercase flex items-center gap-2"><Download size={12}/> PDF</button>
                             </div>
                         )}
                    </div>

                    {/* Exit Map Styled Button */}
                    <div className="flex items-center bg-black/50 p-1 rounded-sm border border-zinc-800">
                         <div className="p-1.5 text-zinc-500"><LogOut size={16} /></div>
                         <button 
                             onClick={() => setIsMindMapMode(false)}
                             className="bg-transparent text-xs text-[#ff003c] outline-none cursor-pointer font-mono uppercase w-[120px] text-left hover:text-white transition-colors"
                         >
                             EXIT MAP
                         </button>
                    </div>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-20 cursor-grab active:cursor-grabbing">
                       <svg width="2400" height="1800" viewBox="-400 -900 2400 1800" style={{ transform: `scale(${mapZoom})`, transition: 'transform 0.2s' }}>
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus, LogOut } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const abortMapRef = useRef<boolean>(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                    <div className="flex items-center">
                        <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                        <select 
                            value={activeFilter} 
                            onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="all">ALL ITEMS</option>
                            <option value="word">WORDS</option>
                            <option value="phrase">PHRASES</option>
                            <option value="sentence">SENTENCES</option>
                        </select>
                    </div>
                    <div className="w-[1px] h-4 bg-zinc-700"></div>
                    <div className="flex items-center">
                        <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                        <select 
                            value={sortOrder} 
                            onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="newest">NEWEST</option>
                            <option value="oldest">OLDEST</option>
                            <option value="az">A-Z</option>
                            <option value="za">Z-A</option>
                        </select>
                    </div>
               </div>

               <button 
                  onClick={handleInitiateMindMap} 
                  disabled={filteredItems.length === 0} 
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}
               >
                   {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                   {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
               </button>
           </div>
       </div>

       {isMindMapMode ? (
           <div className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" ref={mapContainerRef}>
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               {/* Floating Controls in Top Right */}
               <div className="absolute top-4 right-4 flex gap-2 z-50">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0"><ZoomIn size={16}/></button>

                    {/* Separate Export Buttons */}
                    <button onClick={exportToXmind} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to Xmind"><Share2 size={16}/></button>
                    <button onClick={exportToDocx} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to Docx"><FileText size={16}/></button>
                    <button onClick={exportToPdf} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to PDF"><Download size={16}/></button>

                    {/* Exit Map Button */}
                    <button onClick={() => setIsMindMapMode(false)} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#ff003c] text-[#ff003c] rounded-full transition-colors shadow-lg shrink-0" title="Exit Map"><X size={16}/></button>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-20 cursor-grab active:cursor-grabbing">
                       <svg width="2400" height="1800" viewBox="-400 -900 2400 1800" style={{ transform: `scale(${mapZoom})`, transition: 'transform 0.2s' }}>
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};
